import{_ as a,n as t,p as r,a8 as i}from"./framework-520e1760.js";const n={};function o(s,e){return t(),r("div",null,e[0]||(e[0]=[i('<h1 id="machine-readable-security-data-sbom-vex" tabindex="-1"><a class="header-anchor" href="#machine-readable-security-data-sbom-vex" aria-hidden="true">#</a> Machine-Readable Security Data (SBOM, VEX)</h1><p>TuxCare provides machine-readable security data for ELS for Open-Source Applications in the following formats:</p><ul><li><strong>SBOM (Software Bill of Materials)</strong> - package composition and dependency inventory in SPDX and CycloneDX formats</li><li><strong>VEX (Vulnerability Exploitability eXchange)</strong> - exploitability status for known CVEs in CycloneDX VEX format</li></ul><p>Released fixes are available via <a href="https://tuxcare.com/cve-tracker/" target="_blank" rel="noopener noreferrer">tuxcare.com/cve-tracker</a> and <a href="https://security.tuxcare.com/" target="_blank" rel="noopener noreferrer">security.tuxcare.com</a>.</p><h2 id="software-bill-of-materials-sbom" tabindex="-1"><a class="header-anchor" href="#software-bill-of-materials-sbom" aria-hidden="true">#</a> Software Bill of Materials (SBOM)</h2><p>Each application package built by TuxCare ships with an SBOM that lists its components, versions, and dependency relationships. SBOMs are provided in industry-standard formats — SPDX and CycloneDX — so they can be consumed by any SBOM-aware scanner or supply-chain tool.</p><p>To check whether an SBOM is available for a specific application or to request a copy, reach out to <a href="mailto:sales@tuxcare.com">sales@tuxcare.com</a>.</p><h2 id="vulnerability-exploitability-exchange-vex" tabindex="-1"><a class="header-anchor" href="#vulnerability-exploitability-exchange-vex" aria-hidden="true">#</a> Vulnerability Exploitability eXchange (VEX)</h2><p>TuxCare publishes VEX as CycloneDX VEX documents, distributed alongside each package version and updated with every release. The feed is available at <a href="https://security.tuxcare.com/vex/cyclonedx/" target="_blank" rel="noopener noreferrer">security.tuxcare.com/vex/cyclonedx</a>. A VEX document tells you which known CVEs actually affect a given artifact version and which don&#39;t, so scanner results stay focused on real exposure.</p><p>Each entry links one CVE to one artifact version and carries a status:</p><ul><li><strong>exploitable</strong> - the CVE affects this artifact version and has not yet been patched in this release.</li><li><strong>resolved</strong> - the CVE has been patched through a TuxCare release.</li></ul><p>The feed covers every supported base version, every released <code>-tuxcare.N</code> iteration, and transitive dependencies, so the entry count reflects all of these combinations rather than the number of unique CVEs. When checking coverage, filter to the artifact versions you actually use — usually the latest <code>-tuxcare.N</code> iteration of your chosen base version. Earlier iterations remain in the feed for historical completeness but aren&#39;t relevant once you&#39;ve adopted a newer release.</p>',12)]))}const c=a(n,[["render",o],["__file","index.html.vue"]]);export{c as default};
